import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, exceptions
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from datetime import datetime

# Configuration
COSMOS_DB_ENDPOINT = "your_cosmos_db_endpoint"
COSMOS_DB_KEY = "your_cosmos_db_key"
DATABASE_NAME = "your_database_name"
CONTAINER_NAME = "your_container_name"
EVENT_GRID_TOPIC_ENDPOINT = "your_event_grid_topic_endpoint"

def main(myblob: func.InputStream, context: func.Context):
    logging.info(f"Python Blob trigger function processed blob \n"
                 f"Name: {myblob.name}\n"
                 f"Blob Size: {myblob.length} bytes")

    # Process the file content
    file_content = myblob.read().decode('utf-8')
    processed_data = process_file(file_content)

    # Write to Cosmos DB
    write_to_cosmos(processed_data, context.invocation_id)

    # Send notification via Event Grid
    send_event_grid_notification(context.invocation_id)

def process_file(content):
    # Implement your file processing logic here
    return {"processed_data": content.upper()}

def write_to_cosmos(data, invocation_id):
    client = CosmosClient(COSMOS_DB_ENDPOINT, COSMOS_DB_KEY)
    database = client.get_database_client(DATABASE_NAME)
    container = database.get_container_client(CONTAINER_NAME)

    item = {
        "id": invocation_id,
        "data": data,
        "timestamp": datetime.utcnow().isoformat()
    }

    try:
        container.create_item(body=item)
        logging.info("Data written to Cosmos DB successfully.")
    except exceptions.CosmosResourceExistsError:
        logging.error("Item with the same ID already exists in Cosmos DB.")

def send_event_grid_notification(invocation_id):
    event = EventGridEvent(
        id=invocation_id,
        data={"message": "File processed and stored"},
        subject="BlobProcessing",
        event_type="ProcessedFileEvent",
        source="/blob/processing",
        data_version="1.0"
    )

    with EventGridPublisherClient.from_connection_string(EVENT_GRID_TOPIC_ENDPOINT) as client:
        try:
            client.send([event])
            logging.info("Notification sent via Event Grid successfully.")
        except Exception as ex:
            logging.error(f"Failed to send event: {ex}")